import React, { useState } from "react";
import { Container, Paper, Typography, TextField, Button, Alert, CircularProgress } from "@mui/material";
import { useNavigate } from "react-router-dom";
import { sendOtp, verifyOtp, checkRiderApproval } from "../services/api";

export default function RiderLogin() {
  const navigate = useNavigate();
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: "", text: "" });

  const handleSendOtp = async () => {
    setLoading(true);
    setMessage({ type: "", text: "" });
    try {
      // Check admin approval first
      const approval = await checkRiderApproval(mobile);
      if (!approval.data.approved) {
        setMessage({ type: "info", text: "Account pending admin approval. Please wait." });
        return;
      }
      await sendOtp(mobile, "rider");
      setMessage({ type: "success", text: "OTP sent successfully" });
      setStep(2);
    } catch (err) {
      setMessage({ type: "error", text: err.response?.data?.message || "Server error" });
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async () => {
    setLoading(true);
    setMessage({ type: "", text: "" });
    try {
      const res = await verifyOtp(mobile, otp, "rider");
      localStorage.setItem("token", res.data?.user?.token || "");
      setMessage({ type: "success", text: "Login successful!" });
      setTimeout(() => navigate("/rider-dashboard"), 1000);
    } catch (err) {
      setMessage({ type: "error", text: err.response?.data?.message || "Server error" });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Paper sx={{ mt: 6, p: 4, borderRadius: 3, textAlign: "center", boxShadow: 5 }}>
        <Typography variant="h4" sx={{ mb: 2, fontWeight: "bold" }}>Rider Login</Typography>
        {message.text && <Alert severity={message.type} sx={{ mb: 2 }}>{message.text}</Alert>}

        {step === 1 && (
          <>
            <TextField
              fullWidth
              label="Mobile Number"
              value={mobile}
              onChange={e => setMobile(e.target.value)}
              margin="normal"
              inputProps={{ maxLength: 10 }}
              required
            />
            <Button fullWidth variant="contained" sx={{ mt: 2 }} onClick={handleSendOtp} disabled={loading}>
              {loading ? <CircularProgress size={24} color="inherit" /> : "Send OTP"}
            </Button>
          </>
        )}

        {step === 2 && (
          <>
            <TextField
              fullWidth
              label="Enter OTP"
              value={otp}
              onChange={e => setOtp(e.target.value)}
              margin="normal"
              required
            />
            <Button fullWidth variant="contained" sx={{ mt: 2 }} onClick={handleVerifyOtp} disabled={loading}>
              {loading ? <CircularProgress size={24} color="inherit" /> : "Verify OTP"}
            </Button>
          </>
        )}

        <Typography sx={{ mt: 2 }}>
          Don’t have an account?{" "}
          <Button onClick={() => navigate("/rider-register")} sx={{ fontWeight: "bold" }}>Sign Up</Button>
        </Typography>
        <Typography sx={{ mt: 1 }}>
          Login as User?{" "}
          <Button onClick={() => navigate("/user-login")} sx={{ fontWeight: "bold" }}>User Login</Button>
        </Typography>
      </Paper>
    </Container>
  );
}
